const getInitials = (name) =>
  name.replace("Chef ", "").split(" ").map((n) => n[0]).join("").slice(0, 2);

const cardStyles = `
  .rn-card{background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.06);transition:transform .22s,box-shadow .22s;cursor:pointer;}
  .rn-card:hover{transform:translateY(-4px);box-shadow:0 12px 32px rgba(0,0,0,.12);}
  .rn-card-img-wrap{position:relative;height:200px;overflow:hidden;}
  .rn-card-img{width:100%;height:100%;object-fit:cover;transition:transform .4s;display:block;}
  .rn-card:hover .rn-card-img{transform:scale(1.05);}
  .rn-diff-badge{position:absolute;top:12px;left:12px;background:rgba(0,0,0,.55);color:#fff;font-size:11px;font-weight:600;padding:4px 10px;border-radius:6px;}
  .rn-tag-badge{position:absolute;top:12px;right:12px;color:#fff;font-size:10px;font-weight:700;padding:4px 10px;border-radius:6px;letter-spacing:.8px;text-transform:uppercase;}
  .rn-card-body{padding:18px 18px 16px;}
  .rn-card-title{font-family:'Playfair Display',serif;font-size:17px;font-weight:700;color:#1a1a1a;margin-bottom:7px;line-height:1.25;}
  .rn-card-desc{font-size:13px;color:#777;line-height:1.55;margin-bottom:14px;font-weight:300;}
  .rn-card-meta{display:flex;gap:16px;margin-bottom:14px;}
  .rn-meta-item{display:flex;align-items:center;gap:5px;font-size:12px;color:#888;}
  .rn-card-divider{height:1px;background:#f0ede6;margin-bottom:12px;}
  .rn-chef-row{display:flex;align-items:center;gap:8px;}
  .rn-chef-avatar{width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,#e85d2f,#c0392b);display:flex;align-items:center;justify-content:center;font-size:11px;color:#fff;font-weight:700;}
  .rn-chef-name{font-size:12px;color:#e85d2f;font-weight:600;}
`;

export default function RecipeCard({ recipe, onClick }) {
  return (
    <>
      <style>{cardStyles}</style>
      <div className="rn-card" onClick={() => onClick && onClick(recipe)}>
        <div className="rn-card-img-wrap">
          <img className="rn-card-img" src={recipe.image} alt={recipe.title} />
          <span className="rn-diff-badge">{recipe.difficulty}</span>
          <span className="rn-tag-badge" style={{ background: recipe.tagColor }}>{recipe.tag}</span>
        </div>
        <div className="rn-card-body">
          <h3 className="rn-card-title">{recipe.title}</h3>
          <p className="rn-card-desc">{recipe.description}</p>
          <div className="rn-card-meta">
            <span className="rn-meta-item">⏱ {recipe.time}</span>
            <span className="rn-meta-item">👥 {recipe.servings} servings</span>
          </div>
          <div className="rn-card-divider" />
          <div className="rn-chef-row">
            <div className="rn-chef-avatar">{getInitials(recipe.chef)}</div>
            <span className="rn-chef-name">{recipe.chef}</span>
          </div>
        </div>
      </div>
    </>
  );
}
